38	  icon: FC<IconProps>;
39	  /** The completion stage that flips this step from active → done. */
40	  stage: OnboardingStage;
41	  activeText: string;
42	  /**
43	   * Stages whose `status_text` updates belong to *this* step. Listed in
44	   * priority order — the first slot with a value is shown as the live
45	   * sub-message under the step, so a never-cleared earlier stage cannot
46	   * outrank a fresher later stage in the same group.
47	   */
48	  progressFrom: readonly OnboardingStage[];
49	}
