171	
172	  const activeStepIndex = (() => {
173	    for (let i = 0; i < steps.length; i++) {
174	      if (!isStepDone(i)) return i;
175	    }
176	    return steps.length - 1;
177	  })();
178	
179	  return (
180	    <m.div
181	      className="mt-3 flex w-[28rem] flex-col gap-3 rounded-2xl bg-zinc-800/40 p-4 backdrop-blur-xl"
