187	        {steps.map((step, i) => {
188	          const Icon = step.icon;
189	          const isDone = isStepDone(i);
190	          const isActive = i === activeStepIndex && !isDone;
191	          // Each step reads only the status_text emitted by stages in its
192	          // own `progressFrom` group. A late event from another stage can
193	          // no longer bleed into the wrong step's label.
194	          const liveMessage = isActive
195	            ? pickProgressForStep(step, progressByStage)
196	            : undefined;
197	
198	          return (
199	            <m.div
200	              key={step.stage}
201	              className="flex items-center gap-3 justify-between"
