391	function ClarifyDemo() {
392	  // Local reducer so the demo runs against the real state machine. In
393	  // production the questions arrive from the /onboarding/clarify-questions
394	  // endpoint; the demo seeds the mock set on mount so the composer renders
395	  // immediately without a network call.
396	  const [state, dispatch] = useReducer(reducer, initialState, (s) => ({
397	    ...s,
398	    clarifyQuestions: CLARIFY_MOCK_QUESTIONS,
399	    clarifyActiveTab: CLARIFY_MOCK_QUESTIONS[0]?.id ?? null,
