1	/**
2	 * `revealTodos` stage. Active once `onboarding_todos` is non-empty and the
3	 * user hasn't acked yet.
4	 *
5	 * Two sub-states:
6	 * - **Grid mode** (default): show the suggested todos. User can click "Run"
7	 *   on one (→ `executeTodo`, flips into stream mode) or "I'll do it later"
8	 *   (→ `ackTodos`, advances to workflows).
9	 * - **Stream mode** (`state.todoExecutionStarted`): the todo grid is replaced
10	 *   in-place by the live chat stream so the agent's processing is visible
11	 *   without leaving the onboarding shell. Once the agent finishes
12	 *   (`chat.isTodoExecutionDone`) a Continue button dispatches `ackTodoDemo`
13	 *   to advance to the workflows stage.
14	 */
15	
16	"use client";
17	
18	import { Button } from "@heroui/button";
19	import { Mail01Icon } from "@icons";
20	import * as m from "motion/react-m";
21	import type { Dispatch } from "react";
22	import { useCallback } from "react";
23	import { REVEAL_TODOS_INTRO } from "../../constants/messages";
24	import { MOTION_COMPOSER_CTA } from "../../constants/motion";
25	import type { UseOnboardingChatReturn } from "../../hooks/useOnboardingChat";
26	import type { Action, OnboardingState } from "../../state/types";
27	import { OnboardingCTAButton } from "../OnboardingCTAButton";
28	import { OnboardingTodoCards } from "../OnboardingTodoCards";
29	import { RevealIntroBubble } from "../RevealIntroBubble";
30	import { OnboardingChatStream } from "./Chat";
31	
32	interface RevealTodosProps {
33	  state: OnboardingState;
34	  dispatch: Dispatch<Action>;
35	  /** Run-now demo chat — separate throwaway conversation, NOT the welcome
36	   *  conversation. See `useChatStage`. */
37	  chat: UseOnboardingChatReturn;
38	}
39	
40	function generateConvoId(): string {
41	  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
42	    return crypto.randomUUID();
43	  }
44	  return `onboarding-todo-${Date.now()}-${Math.random().toString(36).slice(2)}`;
45	}
46	
47	interface SelectedTodoIndicatorProps {
48	  title: string;
49	  sourceEmail: { sender: string; subject: string } | null;
50	}
51	
52	/** Static "selected todo" indicator rendered above the run-now demo stream.
53	 *  Replaces the previous chat-bubble-shaped TodoRunNowCard so the auto-sent
54	 *  user message never reads as a real conversation turn. */
55	function SelectedTodoIndicator({
56	  title,
57	  sourceEmail,
58	}: SelectedTodoIndicatorProps) {
59	  return (
60	    <div className="rounded-2xl bg-zinc-900 p-3">
61	      <div className="text-xs font-medium tracking-wide text-zinc-500 uppercase">
62	        Selected todo
63	      </div>
64	      <div className="mt-1 text-sm text-zinc-100">{title}</div>
65	      {sourceEmail && (
66	        <div className="mt-3 flex items-start gap-2 rounded-xl bg-zinc-800 p-3">
67	          <Mail01Icon className="mt-0.5 size-3.5 shrink-0 text-zinc-500" />
68	          <div className="min-w-0 flex-1">
69	            <div className="truncate text-xs text-zinc-400">
70	              {sourceEmail.sender}
71	            </div>
72	            <div className="truncate text-xs text-zinc-500">
73	              {sourceEmail.subject}
74	            </div>
75	          </div>
76	        </div>
77	      )}
78	    </div>
79	  );
80	}
81	
82	/** Composer for the `revealTodos` stage. Renders a "Continue" CTA in the
83	 *  pinned footer once the run-now demo finishes — replaces the old inline
84	 *  button that used to sit beneath the todo result. */
85	export function RevealTodosComposer({
86	  dispatch,
87	  chat,
88	}: Pick<RevealTodosProps, "dispatch" | "chat">) {
89	  if (!chat.isTodoExecutionDone) return null;
90	  return (
91	    <m.div className="flex justify-center pb-2" {...MOTION_COMPOSER_CTA}>
92	      <OnboardingCTAButton onClick={() => dispatch({ type: "ackTodoDemo" })}>
93	        Continue
94	      </OnboardingCTAButton>
95	    </m.div>
96	  );
97	}
98	
99	export function RevealTodos({ state, dispatch, chat }: RevealTodosProps) {
100	  const todos = state.server?.onboarding_todos ?? [];
101	
102	  const handleExecute = useCallback(
103	    (todoId: string) => {
104	      const todo = todos.find((t) => t.id === todoId);
105	      if (!todo) return;
106	      const sourceEmail = todo.source_email ?? null;
107	      const emailHint = sourceEmail
108	        ? `\n\n[Context: derived from an email from "${sourceEmail.sender}" with subject "${sourceEmail.subject}". Reference this email and its actual contents.]`
109	        : "";
110	      const closingHint =
111	        "\n\n[This is an onboarding run-now demo. Execute the todo and report the result in 1-2 short sentences. Do NOT ask a follow-up question. Do NOT offer further help or automation. End on the result.]";
112	      const message = `Execute this todo for me: ${todo.title}${emailHint}${closingHint}`;
113	      dispatch({
114	        type: "executeTodo",
115	        message,
116	        convoId: generateConvoId(),
117	        todo: { id: todo.id, title: todo.title, sourceEmail },
118	      });
119	    },
120	    [todos, dispatch],
121	  );
122	
123	  if (todos.length === 0) return null;
124	
125	  if (state.todoExecutionStarted) {
126	    const selected = state.todoExecutionTodo;
127	    return (
128	      <m.div
129	        className="mt-10 w-full space-y-4 rounded-2xl bg-zinc-800/40 p-4 backdrop-blur-xl"
130	        initial={{ opacity: 0 }}
131	        animate={{ opacity: 1 }}
132	        transition={{ duration: 0.3 }}
133	      >
134	        {selected && (
135	          <SelectedTodoIndicator
136	            title={selected.title}
137	            sourceEmail={selected.sourceEmail}
138	          />
139	        )}
140	        <OnboardingChatStream chat={chat} hideRunNowUserMessage />
141	      </m.div>
142	    );
143	  }
144	
145	  return (
146	    <div className="mt-3 space-y-4">
147	      <RevealIntroBubble text={REVEAL_TODOS_INTRO}>
148	        <OnboardingTodoCards
149	          todos={todos.map((t) => ({
150	            id: t.id,
151	            title: t.title,
152	            description: t.description ?? undefined,
153	            source_email: t.source_email ?? undefined,
154	          }))}
155	          onExecuteTodo={handleExecute}
156	          isExecuting={false}
157	          executingTodoId={null}
158	          completedTodoIds={new Set()}
159	        />
160	      </RevealIntroBubble>
161	
162	      <m.div
163	        className="flex justify-center"
