/**
 * Inline holo-card reveal shown above the chat stream. Four-state machine:
 *   idle (giftbox) → vibrating (anticipation) → bursting (scale-up + fade)
 *   → revealed (editable card with confetti)
 *
 * On hover the giftbox scales and lifts slightly, signalling it's interactive.
 * The "bursting" step double-buffers the visuals: the giftbox scales and fades
 * out while the card scales in underneath, so the transition reads as the box
 * opening rather than disappearing flatly.
 */

"use client";

import confetti from "canvas-confetti";
import { AnimatePresence } from "motion/react";
import * as m from "motion/react-m";
import Image from "next/image";
import { useEffect, useRef, useState } from "react";

import { HoloCardEditor } from "@/components/ui/holo-card/HoloCardEditor";
import type { HoloCardDisplayData } from "@/components/ui/holo-card/types";
import { HOLO_CARD_HEIGHT, HOLO_CARD_WIDTH } from "../../constants";
import type { PersonalizationData } from "../../types/websocket";

interface HoloCardRevealProps {
  personalizationData: PersonalizationData;
}

type RevealState = "idle" | "vibrating" | "bursting" | "revealed";

// Container is sized to the holo card so the giftbox and the revealed card
// share an anchor — no layout jump when the state flips.
const GIFTBOX_SRC = "/images/onboarding/giftbox.png";

export function HoloCardReveal({ personalizationData }: HoloCardRevealProps) {
  const [revealState, setRevealState] = useState<RevealState>("idle");
  const cardWrapRef = useRef<HTMLDivElement>(null);

  // Choreography on reveal:
  //   t=0    card mounts, springs in from scale 0.6
  //   t=40   smooth scroll kicks off so the card is in view as it grows
  //   t=520  scroll has settled — fire confetti from the card's actual
  //          on-screen centre so the burst lands ON the card, not on the
  //          original (pre-scroll) viewport position
  // Times are deliberately offset; firing confetti before the scroll settles
  // makes the particles spawn at a stale origin and look detached.
  useEffect(() => {
    if (revealState !== "revealed") return;
    const scrollTimer = window.setTimeout(() => {
      cardWrapRef.current?.scrollIntoView({
        behavior: "smooth",
        block: "center",
      });
    }, 40);
    const confettiTimer = window.setTimeout(() => {
      const node = cardWrapRef.current;
      const origin = node
        ? (() => {
            const rect = node.getBoundingClientRect();
            return {
              x: (rect.left + rect.width / 2) / window.innerWidth,
              y: (rect.top + rect.height / 2) / window.innerHeight,
            };
          })()
        : { x: 0.5, y: 0.55 };
      confetti({
        particleCount: 160,
        spread: 80,
        startVelocity: 45,
        origin,
      });
    }, 520);
    return () => {
      window.clearTimeout(scrollTimer);
      window.clearTimeout(confettiTimer);
    };
  }, [revealState]);

  const holoCardData: HoloCardDisplayData = {
    house: personalizationData.house ?? "bluehaven",
    name: personalizationData.name ?? "User",
    personality_phrase:
      personalizationData.personality_phrase ?? "Curious Adventurer",
    user_bio:
      personalizationData.user_bio ??
      "A passionate individual exploring new possibilities and making an impact.",
    account_number: personalizationData.account_number
      ? `#${personalizationData.account_number}`
      : "#00000",
    member_since:
      personalizationData.member_since ??
      new Date().toLocaleDateString("en-US", {
        month: "short",
        day: "numeric",
        year: "numeric",
      }),
    overlay_color: personalizationData.overlay_color ?? "rgba(0,0,0,0)",
    overlay_opacity: personalizationData.overlay_opacity ?? 40,
    holo_card_id: personalizationData.holo_card_id,
  };

  const handleGiftboxClick = () => {
    if (revealState !== "idle") return;
    setRevealState("vibrating");
  };

  const handleVibrationComplete = () => {
    setRevealState("bursting");
  };

  const handleBurstComplete = () => {
    setRevealState("revealed");
  };

  return (
    <m.div
      className="flex flex-col items-center py-2"
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.35 }}
    >
      <div
        className="relative flex items-center justify-center"
        style={{
          width: HOLO_CARD_WIDTH,
          minHeight: revealState === "revealed" ? HOLO_CARD_HEIGHT : "auto",
        }}
      >
        <AnimatePresence mode="wait">
          {revealState !== "revealed" && (
            <m.button
              key="giftbox"
              type="button"
              aria-label="Tap to reveal your personalized GAIA card"
              onClick={handleGiftboxClick}
              disabled={revealState !== "idle"}
              className="group relative flex cursor-pointer items-center justify-center bg-transparent outline-none"
              style={{ perspective: 1000 }}
              initial={{ opacity: 0, scale: 0.9 }}
              animate={
                revealState === "vibrating"
                  ? {
                      opacity: 1,
                      scale: [1, 1.04, 1.04, 1, 1, 1, 1, 1],
                      rotate: [0, -8, 8, -10, 10, -6, 6, -3, 3, 0],
                      x: [0, -4, 4, -6, 6, -4, 4, -2, 2, 0],
                    }
                  : revealState === "bursting"
                    ? {
                        opacity: [1, 1, 0],
                        scale: [1, 1.3, 1.6],
                        rotate: 0,
                        x: 0,
                      }
                    : { opacity: 1, scale: 1, rotate: 0, x: 0 }
              }
              whileHover={
                revealState === "idle" ? { scale: 1.06, y: -6 } : undefined
              }
              whileTap={revealState === "idle" ? { scale: 0.97 } : undefined}
              transition={
                revealState === "vibrating"
                  ? { duration: 0.7, ease: "easeInOut" }
                  : revealState === "bursting"
                    ? { duration: 0.45, ease: "easeOut" }
                    : { type: "spring", stiffness: 320, damping: 22 }
              }
              onAnimationComplete={
                revealState === "vibrating"
                  ? handleVibrationComplete
                  : revealState === "bursting"
                    ? handleBurstComplete
                    : undefined
              }
            >
              <m.div
                className="relative flex flex-col items-center"
                style={{ width: HOLO_CARD_WIDTH }}
                animate={revealState === "idle" ? { y: [0, -6, 0] } : { y: 0 }}
                transition={
                  revealState === "idle"
                    ? { duration: 3, repeat: Infinity, ease: "easeInOut" }
                    : undefined
                }
              >
                <Image
                  src={GIFTBOX_SRC}
                  alt=""
                  width={1360}
                  height={952}
                  priority
                  className="h-auto w-[240px] select-none"
                  draggable={false}
                />
                {revealState === "idle" && (
                  <m.p
                    className="mt-4 text-sm text-white/80"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: [0.5, 1, 0.5] }}
                    transition={{ duration: 2.4, repeat: Infinity }}
                  >
                    Click to open
                  </m.p>
                )}
              </m.div>
            </m.button>
          )}

          {revealState === "revealed" && (
            <m.div
              key="card"
              ref={cardWrapRef}
              className="flex flex-col items-center gap-4"
              role="img"
              aria-label="Your personalized GAIA member card"
              initial={{ opacity: 0, scale: 0.6 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{
                type: "spring",
                stiffness: 220,
                damping: 18,
                delay: 0.05,
              }}
            >
              <HoloCardEditor
                initialData={holoCardData}
                height={HOLO_CARD_HEIGHT}
                width={HOLO_CARD_WIDTH}
              />
              <p className="text-sm text-zinc-400">Click to flip card</p>
            </m.div>
          )}
        </AnimatePresence>
      </div>
    </m.div>
  );
}

/**
 * Persona-specific welcome copy rendered as the single post-onboarding bot
 * message. Each entry is one string with `<NEW_MESSAGE_BREAK>` splits — the
 * shared bot bubble renderer staggers each segment into its own bubble.
 *
 * Keys are the canonical `profession` values from `professionOptions` in
 * `apps/web/src/features/onboarding/constants/index.ts`. Direct lookup, no
 * fuzzy matching — anything missing falls through to `FALLBACK_COPY`.
 */

const GREETING = "Hey, welcome! I'm your GAIA (general-purpose ai assistant).";

interface PersonaEntry {
  /** Verb-led middle bubble — what GAIA can do for this persona. */
  middle: string;
  /** Tool/integration close — names the integrations the persona should
   *  connect to switch the actions on. */
  close: string;
}

const ENTRIES: Record<string, PersonaEntry> = {
  developer: {
    middle:
      "I can triage your open PRs, prep your standup notes, and summarize the Slack threads you've been ignoring.",
    close: "Just connect GitHub and Linear and I'll get to it!",
  },
  engineer: {
    middle:
      "I can triage your open PRs, prep your standup notes, and summarize the Slack threads you've been ignoring.",
    close: "Just connect GitHub and Linear and I'll get to it!",
  },
  designer: {
    middle:
      "I can draft client check-ins, turn loose feedback into todos, and call out projects gathering dust.",
    close: "Just connect Notion and Slack and I'll get to it!",
  },
  artist: {
    middle:
      "I can draft client check-ins, turn loose feedback into todos, and call out projects gathering dust.",
    close: "Just connect Notion and Slack and I'll get to it!",
  },
  manager: {
    middle:
      "I can write your weekly status updates, prep standups from yesterday's threads, and call out work that's slipping.",
    close: "Just connect Linear and Slack and I'll get to it!",
  },
  analyst: {
    middle:
      "I can write your weekly status updates, prep standups from yesterday's threads, and call out work that's slipping.",
    close: "Just connect Linear and Slack and I'll get to it!",
  },
  consultant: {
    middle:
      "I can write your weekly status updates, prep standups from yesterday's threads, and call out work that's slipping.",
    close: "Just connect Linear and Slack and I'll get to it!",
  },
  entrepreneur: {
    middle:
      "I can draft investor updates, prep your meeting notes, and pull together what needs your attention this week.",
    close: "Just connect Calendar and Notion and I'll get to it!",
  },
  researcher: {
    middle:
      "I can rank your drafts by readiness, pull research when you're stuck, and resurface notes you forgot you wrote.",
    close: "Just connect Notion and Google Docs and I'll get to it!",
  },
  writer: {
    middle:
      "I can rank your drafts by readiness, pull research when you're stuck, and resurface notes you forgot you wrote.",
    close: "Just connect Notion and Google Docs and I'll get to it!",
  },
  marketing: {
    middle:
      "I can draft follow-ups in your voice, surface deals waiting on you, and watch competitor moves while you sleep.",
    close: "Just connect HubSpot and Notion and I'll get to it!",
  },
  sales: {
    middle:
      "I can draft follow-ups in your voice, surface deals waiting on you, and watch competitor moves while you sleep.",
    close: "Just connect HubSpot and Notion and I'll get to it!",
  },
  student: {
    middle:
      "I can flag upcoming deadlines, draft your weekly study plan, and summarize the readings you haven't opened.",
    close: "Just connect Calendar and Notion and I'll get to it!",
  },
  teacher: {
    middle:
      "I can draft lesson plans, summarize student emails, and tell you what needs grading first.",
    close: "Just connect Calendar and Google Docs and I'll get to it!",
  },
  doctor: {
    middle:
      "I can prep for tomorrow's meetings, summarize long client threads, and flag anything overdue before it bites.",
    close: "Just connect Calendar and Gmail and I'll get to it!",
  },
  lawyer: {
    middle:
      "I can prep for tomorrow's meetings, summarize long client threads, and flag anything overdue before it bites.",
    close: "Just connect Calendar and Gmail and I'll get to it!",
  },
  accountant: {
    middle:
      "I can prep for tomorrow's meetings, summarize long client threads, and flag anything overdue before it bites.",
    close: "Just connect Calendar and Gmail and I'll get to it!",
  },
  freelancer: {
    middle:
      "I can triage client requests, draft updates in your voice, and flag invoices that are slipping.",
    close: "Just connect Calendar and Gmail and I'll get to it!",
  },
};

const FALLBACK: PersonaEntry = {
  middle:
    "I can draft messages, prep your week, and surface things that need your attention.",
  close: "Just connect a few tools and I'll get to it!",
};

function build({ middle, close }: PersonaEntry): string {
  return `${GREETING}<NEW_MESSAGE_BREAK>${middle}<NEW_MESSAGE_BREAK>${close}`;
}

/** Resolve the welcome bubble copy for a profession value. Direct lookup
 *  against the canonical `professionOptions` list — `retired`, `other`,
 *  `null`, `undefined`, and anything unknown all hit the fallback. */
export function getWelcomeCopyForProfession(
  profession: string | null | undefined,
): string {
  if (!profession) return build(FALLBACK);
  const entry = ENTRIES[profession];
  return entry ? build(entry) : build(FALLBACK);
}

