                  ? {
                      opacity: 1,
                      scale: [1, 1.04, 1.04, 1, 1, 1, 1, 1],
                      rotate: [0, -8, 8, -10, 10, -6, 6, -3, 3, 0],
                      x: [0, -4, 4, -6, 6, -4, 4, -2, 2, 0],
